let points = 100;
points += 50;   // 150
points -= 30;   // 120
points *= 2;    // 240
console.log(points);

const age = 20;
const hasId = true;
console.log(age >= 18 && hasId);  // true الشرطان صحيحان
console.log(age < 18 || hasId);   // true أحدهما يكفي
console.log(!hasId);              // false معكوس

const status = age >= 18 ? "بالغ" : "قاصر";
console.log(status);
